"use client";

import { useState, useEffect } from "react";
import { Treemap, ResponsiveContainer } from "recharts";
import { fetchThemeTrend } from "@/lib/api";
import type { ThemeGroup, ThemeTrendResponse } from "@/types";

type SortMode = "change_rate" | "volume";
type PeriodMode = "daily" | "weekly";

function getColor(value: number, max: number): string {
  if (max <= 0) return "#8844cc";
  const ratio = value / max;
  if (ratio > 0.7) return "#cc0000";
  if (ratio > 0.4) return "#e63333";
  if (ratio > 0.2) return "#ff6644";
  return "#8844cc";
}

interface TreemapContentProps {
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  name?: string;
  avgChangeRate?: number;
  fillColor?: string;
}

function ThemeTreemapContent(props: TreemapContentProps) {
  const { x = 0, y = 0, width = 0, height = 0, name = "", avgChangeRate = 0, fillColor = "#8844cc" } = props;
  if (width < 40 || height < 30) return null;
  return (
    <g>
      <rect x={x} y={y} width={width} height={height} fill={fillColor} rx={4} />
      <text
        x={x + width / 2}
        y={y + height / 2 - 8}
        textAnchor="middle"
        fill="#fff"
        fontSize={Math.min(14, width / 6)}
        fontWeight="bold"
      >
        {name}
      </text>
      <text
        x={x + width / 2}
        y={y + height / 2 + 10}
        textAnchor="middle"
        fill="#fff"
        fontSize={Math.min(12, width / 7)}
      >
        {avgChangeRate > 0 ? "+" : ""}{avgChangeRate.toFixed(1)}%
      </text>
    </g>
  );
}

function ThemeSkeleton() {
  return (
    <div className="w-full h-64 bg-white/5 border border-white/10 rounded-xl animate-pulse flex items-center justify-center text-gray-500 text-sm">
      테마 트렌드 로딩 중...
    </div>
  );
}

export default function ThemeTrend() {
  const [sort, setSort] = useState<SortMode>("change_rate");
  const [period, setPeriod] = useState<PeriodMode>("daily");
  const [response, setResponse] = useState<ThemeTrendResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    setLoading(true);
    setError("");
    setResponse(null);
    fetchThemeTrend(sort, period)
      .then(setResponse)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  }, [sort, period]);

  const groups: ThemeGroup[] = response?.groups ?? [];

  const treemapData = groups.map((g) => {
    const maxVal =
      sort === "change_rate"
        ? Math.max(...groups.map((d) => d.avg_change_rate), 0.01)
        : Math.max(...groups.map((d) => d.total_volume), 1);
    const val = sort === "change_rate" ? g.avg_change_rate : g.total_volume;
    return {
      name: g.theme,
      value: sort === "change_rate" ? Math.max(g.avg_change_rate, 0.1) : Math.max(g.total_volume, 1),
      avgChangeRate: g.avg_change_rate,
      fillColor: getColor(Math.max(val, 0), maxVal),
    };
  });

  // 서브타이틀: 거래일 정보 표시
  const subtitle = response?.trade_date
    ? `${response.trade_date} 기준 · 최근 거래일`
    : "최근 거래일 기준";

  return (
    <section>
      {/* 헤더 */}
      <div className="flex items-center justify-between mb-2">
        <div>
          <h2 className="text-lg font-bold">오늘의 테마 트렌드</h2>
          <p className="text-xs text-gray-400">{loading ? "데이터 로딩 중..." : subtitle}</p>
        </div>
        {/* 정렬 기준 */}
        <div className="flex gap-1">
          <button
            type="button"
            onClick={() => setSort("change_rate")}
            className={`text-xs px-3 py-1.5 rounded-lg transition-colors ${
              sort === "change_rate"
                ? "bg-skyblue/20 text-skyblue"
                : "text-gray-400 hover:text-white hover:bg-white/5"
            }`}
          >
            상승률 기준
          </button>
          <button
            type="button"
            onClick={() => setSort("volume")}
            className={`text-xs px-3 py-1.5 rounded-lg transition-colors ${
              sort === "volume"
                ? "bg-skyblue/20 text-skyblue"
                : "text-gray-400 hover:text-white hover:bg-white/5"
            }`}
          >
            거래대금 기준
          </button>
        </div>
      </div>

      {/* 기간 선택 버튼 */}
      <div className="flex gap-1 mb-3">
        <button
          type="button"
          onClick={() => setPeriod("daily")}
          className={`text-xs px-4 py-1.5 rounded-lg border transition-colors ${
            period === "daily"
              ? "bg-white/15 border-white/30 text-white font-medium"
              : "border-white/10 text-gray-400 hover:text-white hover:bg-white/5"
          }`}
        >
          오늘 기준
        </button>
        <button
          type="button"
          onClick={() => setPeriod("weekly")}
          className={`text-xs px-4 py-1.5 rounded-lg border transition-colors ${
            period === "weekly"
              ? "bg-white/15 border-white/30 text-white font-medium"
              : "border-white/10 text-gray-400 hover:text-white hover:bg-white/5"
          }`}
        >
          주간 기준
        </button>
      </div>

      {loading ? (
        <ThemeSkeleton />
      ) : error ? (
        <div className="w-full h-32 bg-white/5 border border-white/10 rounded-xl flex items-center justify-center text-gray-400 text-sm">
          {error}
        </div>
      ) : treemapData.length === 0 ? (
        <div className="w-full h-32 bg-white/5 border border-white/10 rounded-xl flex items-center justify-center text-gray-400 text-sm">
          거래 데이터를 불러올 수 없습니다
        </div>
      ) : (
        <div className="w-full h-64 bg-white/5 border border-white/10 rounded-xl overflow-hidden p-1">
          <ResponsiveContainer width="100%" height="100%">
            <Treemap
              data={treemapData}
              dataKey="value"
              aspectRatio={4 / 3}
              content={<ThemeTreemapContent />}
            />
          </ResponsiveContainer>
        </div>
      )}
    </section>
  );
}
