"use client";

import { useState, useEffect } from "react";
import { fetchKeywordFeed } from "@/lib/api";
import type { KeywordFeedResponse, KeywordStock } from "@/types";
import Link from "next/link";
import { Search } from "lucide-react";

const STORAGE_KEY = "stockcock_custom_keywords";

export default function KeywordFeed() {
  const [kw1, setKw1] = useState("");
  const [kw2, setKw2] = useState("");
  const [feed, setFeed] = useState<KeywordFeedResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // localStorage 복원
  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const { kw1: k1, kw2: k2 } = JSON.parse(saved);
        if (k1) setKw1(k1);
        if (k2) setKw2(k2);
        // 저장된 키워드로 자동 조회
        const kws = [k1, k2].filter(Boolean).join(",");
        if (kws) {
          setLoading(true);
          fetchKeywordFeed(kws)
            .then(setFeed)
            .catch((e) => setError(e.message))
            .finally(() => setLoading(false));
        }
      }
    } catch {
      // localStorage 접근 실패 시 무시
    }
  }, []);

  const handleApply = () => {
    const kws = [kw1, kw2].filter((k) => k.trim()).join(",");
    if (!kws) return;

    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ kw1: kw1.trim(), kw2: kw2.trim() }));
    } catch {
      // 무시
    }

    setLoading(true);
    setError("");
    fetchKeywordFeed(kws)
      .then(setFeed)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  return (
    <section>
      <h2 className="text-lg font-bold mb-3">내 관심 키워드</h2>

      {/* 입력 영역 */}
      <div className="bg-white/5 border border-white/10 rounded-xl p-4 space-y-3">
        <div className="flex gap-2">
          <input
            type="text"
            value={kw1}
            onChange={(e) => setKw1(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleApply()}
            placeholder="키워드 입력 예: AI"
            className="flex-1 bg-white/10 border border-white/10 rounded-lg px-3 py-2 text-sm placeholder:text-gray-500 focus:outline-none focus:border-skyblue/50"
          />
          <input
            type="text"
            value={kw2}
            onChange={(e) => setKw2(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleApply()}
            placeholder="키워드 입력 예: 반도체"
            className="flex-1 bg-white/10 border border-white/10 rounded-lg px-3 py-2 text-sm placeholder:text-gray-500 focus:outline-none focus:border-skyblue/50"
          />
          <button
            type="button"
            onClick={handleApply}
            disabled={loading || (!kw1.trim() && !kw2.trim())}
            className="px-4 py-2 bg-skyblue/20 text-skyblue rounded-lg text-sm hover:bg-skyblue/30 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1.5"
          >
            <Search className="w-4 h-4" />
            키워드 적용하기
          </button>
        </div>
      </div>

      {/* 결과 영역 */}
      {loading && (
        <div className="mt-4 space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-16 bg-white/5 border border-white/10 rounded-xl animate-pulse" />
          ))}
        </div>
      )}

      {error && (
        <div className="mt-4 text-sm text-red-400 bg-red-400/10 border border-red-400/20 rounded-xl p-3">
          {error}
        </div>
      )}

      {!loading && feed && (
        <div className="mt-4 space-y-5">
          {/* 관련 종목 */}
          {feed.stocks.length > 0 && (
            <div>
              <h3 className="text-sm font-semibold text-gray-300 mb-2">관련 종목 <span className="text-xs text-gray-500 font-normal">AI 추천 · 실제 상장 검증 완료</span></h3>
              <div className="space-y-2">
                {(feed.stocks as KeywordStock[]).map((s) => (
                  <Link
                    key={s.code}
                    href={`/stock/${s.code}`}
                    className="block bg-white/5 border border-white/10 rounded-xl p-3 hover:bg-white/10 transition-colors"
                  >
                    <div className="flex items-center justify-between gap-3">
                      <div className="min-w-0">
                        <div className="flex items-center gap-2">
                          <p className="text-sm font-medium truncate">{s.name}</p>
                          <p className="text-xs text-gray-400">{s.code}</p>
                          {s.current_price != null && (
                            <span className={`text-xs font-medium ${(s.change_rate ?? 0) >= 0 ? "text-green-400" : "text-red-400"}`}>
                              {(s.change_rate ?? 0) >= 0 ? "+" : ""}{(s.change_rate ?? 0).toFixed(1)}%
                            </span>
                          )}
                        </div>
                        <p className="text-xs text-gray-400 mt-0.5 line-clamp-1">{s.reason}</p>
                      </div>
                      {s.current_price != null && (
                        <p className="text-sm font-medium text-right whitespace-nowrap">{s.current_price.toLocaleString()}원</p>
                      )}
                    </div>
                  </Link>
                ))}
              </div>
            </div>
          )}

          {/* 관련 뉴스 */}
          {feed.news.length > 0 && (
            <div>
              <h3 className="text-sm font-semibold text-gray-300 mb-2">관련 뉴스</h3>
              <div className="space-y-2">
                {feed.news.map((n) => (
                  <Link
                    key={n.id}
                    href={`/issues/${encodeURIComponent(n.id)}`}
                    className="block bg-white/5 border border-white/10 rounded-xl p-3 hover:bg-white/10 transition-colors"
                  >
                    <p className="text-sm font-medium line-clamp-2">{n.title}</p>
                    <p className="text-xs text-gray-400 mt-1">
                      {n.source} &middot; {new Date(n.published_at).toLocaleDateString("ko-KR")}
                    </p>
                  </Link>
                ))}
              </div>
            </div>
          )}

          {/* 관련 정책 */}
          {feed.policies.length > 0 && (
            <div>
              <h3 className="text-sm font-semibold text-gray-300 mb-2">관련 정책</h3>
              <div className="space-y-2">
                {feed.policies.map((p) => (
                  <Link
                    key={p.id}
                    href={`/policy/${p.id}`}
                    className="block bg-white/5 border border-white/10 rounded-xl p-3 hover:bg-white/10 transition-colors"
                  >
                    <p className="text-sm font-medium line-clamp-2">{p.title}</p>
                    <p className="text-xs text-gray-400 mt-1">{p.department}</p>
                  </Link>
                ))}
              </div>
            </div>
          )}

          {feed.stocks.length === 0 && feed.news.length === 0 && feed.policies.length === 0 && (
            <p className="text-sm text-gray-400 text-center py-4">해당 키워드의 결과가 없습니다.</p>
          )}
        </div>
      )}
    </section>
  );
}
